        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
    };
    if levy.exit_code != 0 {
        return rbtdre_Verdict::Fail(format!(
            "depot levy exit {}\n{}",
            levy.exit_code, levy.stderr
        ));
