        &[],
        dir,
        "mantle",
    ) {
        Ok(r) => r,
        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
    };
    if mantle.exit_code != 0 {
        return rbtdre_Verdict::Fail(format!(
